// ShareActivity.kt
package com.example.sharehandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import java.io.File
import java.io.FileOutputStream

class ShareActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        if (!isTaskRoot && intent.hasCategory(Intent.CATEGORY_LAUNCHER) && 
            intent.action != null && intent.action == Intent.ACTION_MAIN) {
            finish()
            return
        }

        when (intent?.action) {
            Intent.ACTION_SEND -> {
                handleSendIntent(intent)
            }
            Intent.ACTION_SEND_MULTIPLE -> {
                handleSendMultipleIntent(intent)
            }
            else -> {
                Toast.makeText(this, "Unsupported action", Toast.LENGTH_SHORT).show()
                finish()
            }
        }
    }

    private fun handleSendIntent(intent: Intent) {
        val type = intent.type ?: run {
            Toast.makeText(this, "No content type", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        when {
            type.startsWith("text/") -> {
                handleSharedText(intent)
            }
            type.startsWith("image/") -> {
                handleSharedImage(intent)
            }
            else -> {
                Toast.makeText(this, "Unsupported content type: $type", Toast.LENGTH_SHORT).show()
                finish()
            }
        }
    }

    private fun handleSendMultipleIntent(intent: Intent) {
        val type = intent.type ?: run {
            Toast.makeText(this, "No content type", Toast.LENGTH_SHORT).show()
            finish()
            return
        }

        if (type.startsWith("image/")) {
            handleSharedMultipleImages(intent)
        } else {
            Toast.makeText(this, "Unsupported content type: $type", Toast.LENGTH_SHORT).show()
            finish()
        }
    }

    private fun handleSharedText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        
        if (sharedText != null) {
            if (isValidUrl(sharedText)) {
                processUrl(sharedText)
            } else {
                processText(sharedText)
            }
        } else {
            Toast.makeText(this, "No text content found", Toast.LENGTH_SHORT).show()
            finish()
        }
    }

    private fun handleSharedImage(intent: Intent) {
        val imageUri = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableExtra(Intent.EXTRA_STREAM)
        }

        if (imageUri != null && isValidUri(imageUri)) {
            processImage(imageUri)
        } else {
            Toast.makeText(this, "Invalid image URI", Toast.LENGTH_SHORT).show()
            finish()
        }
    }

    private fun handleSharedMultipleImages(intent: Intent) {
        val imageUris = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.TIRAMISU) {
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
        } else {
            @Suppress("DEPRECATION")
            intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        }

        if (imageUris != null && imageUris.isNotEmpty()) {
            val validUris = imageUris.filter { isValidUri(it) }
            if (validUris.isNotEmpty()) {
                processMultipleImages(validUris)
            } else {
                Toast.makeText(this, "No valid image URIs found", Toast.LENGTH_SHORT).show()
                finish()
            }
        } else {
            Toast.makeText(this, "No images found", Toast.LENGTH_SHORT).show()
            finish()
        }
    }

    private fun isValidUrl(url: String): Boolean {
        return try {
            val uri = Uri.parse(url)
            uri.scheme != null && (uri.scheme == "http" || uri.scheme == "https")
        } catch (e: Exception) {
            false
        }
    }

    private fun isValidUri(uri: Uri): Boolean {
        return try {
            val scheme = uri.scheme
            scheme != null && (scheme == "content" || scheme == "file")
        } catch (e: Exception) {
            false
        }
    }

    private fun processUrl(url: String) {
        Toast.makeText(this, "Processing URL: $url", Toast.LENGTH_LONG).show()
        
        // Process URL here
        // Example: Download content, open in browser, save to database, etc.
        
        finish()
    }

    private fun processText(text: String) {
        Toast.makeText(this, "Processing text: ${text.take(50)}...", Toast.LENGTH_LONG).show()
        
        // Process text here
        
        finish()
    }

    private fun processImage(imageUri: Uri) {
        try {
            contentResolver.openInputStream(imageUri)?.use { inputStream ->
                val fileName = "shared_image_${System.currentTimeMillis()}.jpg"
                val file = File(filesDir, fileName)
                
                FileOutputStream(file).use { outputStream ->
                    inputStream.copyTo(outputStream)
                }
                
                Toast.makeText(this, "Image saved: ${file.absolutePath}", Toast.LENGTH_LONG).show()
                
                // Process image here
                // Example: Upload to server, apply filters, save to gallery, etc.
            }
        } catch (e: Exception) {
            Toast.makeText(this, "Error processing image: ${e.message}", Toast.LENGTH_SHORT).show()
        } finally {
            finish()
        }
    }

    private fun processMultipleImages(imageUris: List<Uri>) {
        var successCount = 0
        
        imageUris.forEach { uri ->
            try {
                contentResolver.openInputStream(uri)?.use { inputStream ->
                    val fileName = "shared_image_${System.currentTimeMillis()}_${successCount}.jpg"
                    val file = File(filesDir, fileName)
                    
                    FileOutputStream(file).use { outputStream ->
                        inputStream.copyTo(outputStream)
                    }
                    successCount++
                }
            } catch (e: Exception) {
                // Continue processing other images
            }
        }
        
        Toast.makeText(this, "Processed $successCount of ${imageUris.size} images", Toast.LENGTH_LONG).show()
        
        // Process multiple images here
        
        finish()
    }
}